import React, { useState, useEffect } from 'react';
import { Package, Truck, CheckCircle } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1);

  useEffect(() => {
    // Simulamos el progreso
    const timer1 = setTimeout(() => setFase(2), 5000); // 5 seg -> En camino
    const timer2 = setTimeout(() => {
      setFase(3);
      // IMPORTANTE: Después de 2 segundos de estar "Entregado", avisamos al padre
      setTimeout(() => {
        if (onFinalizar) onFinalizar(pedido.id);
      }, 2000);
    }, 10000); // 10 seg -> Entregado

    return () => { clearTimeout(timer1); clearTimeout(timer2); };
  }, [pedido.id, onFinalizar]);

  const pasos = [
    { id: 1, label: 'Confirmado', icon: <Package size={20} /> },
    { id: 2, label: 'En camino', icon: <Truck size={20} /> },
    { id: 3, label: 'Entregado', icon: <CheckCircle size={20} /> }
  ];

  return (
    <div style={container}>
      <div style={stepper}>
        {pasos.map((p) => (
          <div key={p.id} style={{ ...step, color: fase >= p.id ? '#e67e22' : '#cbd5e1' }}>
            <div style={{ ...circle, background: fase >= p.id ? '#e67e22' : '#f1f5f9' }}>
              {React.cloneElement(p.icon, { color: fase >= p.id ? 'white' : '#94a3b8' })}
            </div>
            <span style={{fontSize: '0.7rem'}}>{p.label}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

const container = { background: 'white', padding: '20px', borderRadius: '15px', marginBottom: '10px', border: '1px solid #e2e8f0' };
const stepper = { display: 'flex', justifyContent: 'space-between' };
const step = { display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 };
const circle = { width: '35px', height: '35px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '5px' };

export default SeguimientoPedido;
